INSERT INTO public.coaching_knowledge_sections (topic, subtopic, title, content, intent_tags, stage_tags, priority) VALUES

('investing', 'index_funds_basics',
 'Индексные фонды — основа разумного инвестирования',
 'Индексный фонд (ETF) копирует широкий рынок: S&P 500, MSCI World, FTSE All-World. Преимущества: диверсификация (сотни компаний за один тикер), низкие комиссии (0.05-0.20% годовых vs 1-2% у активных фондов), прозрачность. Историческая доходность мирового рынка акций ~7-10% годовых после инфляции (на длинных горизонтах). Концепция Джона Богла: "не ищи иголку в стоге сена — купи стог". Подходит для долгосрочных целей (10+ лет).',
 '{investment_basics,financial_advice,book_recommendations}', '{saving,investing,fire,*}', 90),

('investing', 'dollar_cost_averaging',
 'Усреднение ценой (DCA)',
 'Инвестируй фиксированную сумму регулярно (раз в месяц), а не пытайся "поймать дно". При просадке рынка купишь больше акций, при росте — меньше. Это сглаживает волатильность и убирает эмоциональное принятие решений. Исследования показывают: lump-sum исторически даёт чуть больше, но DCA лучше для психики и для тех, кто получает доход помесячно. Главный враг инвестора — не рынок, а собственные эмоции.',
 '{investment_basics,financial_advice,impulse_check}', '{saving,investing,fire,*}', 85),

('investing', 'asset_allocation_by_age',
 'Распределение активов по возрасту',
 'Простое правило: процент акций ≈ 110 минус ваш возраст. Например, в 30 лет — 80% акции, 20% облигации. С возрастом доля облигаций растёт (защита капитала важнее роста). Это базовая отправная точка, не догма. Если у вас высокая толерантность к риску и долгий горизонт — можно и 100% акций до 40 лет. Если близко к пенсии — больше защитных инструментов. Главное: не паникуй и не ребалансируй чаще раза в год.',
 '{investment_basics,financial_advice,financial_stage}', '{saving,investing,fire}', 80),

('investing', 'efficient_markets',
 'Гипотеза эффективного рынка',
 'Цены акций уже учитывают всю публичную информацию — поэтому "обыграть рынок" регулярно почти невозможно. Подтверждено десятилетиями исследований: 80-90% активных фондов проигрывают индексу за 10+ лет. Вывод Бертона Малкиела ("A Random Walk Down Wall Street"): не пытайся выбрать "горячие акции" или угадать лучший момент. Купи широкий индекс, держи долго, ребалансируй. Скучно — но работает.',
 '{investment_basics,financial_advice,book_recommendations}', '{investing,fire,*}', 75),

('savings', 'four_percent_rule',
 'Правило 4% (Trinity Study)',
 'Если ежегодно снимать 4% от пенсионного капитала (с учётом инфляции), деньги с вероятностью 95% не закончатся за 30 лет. Значит, для финансовой независимости нужен капитал ≈ 25× ваших годовых расходов. Например, расходы 30 000$/год → цель 750 000$. Это упрощённая формула; современные исследования предлагают более консервативные 3.3-3.5%, но 4% остаётся отправной точкой FIRE-движения.',
 '{savings_advice,financial_advice,financial_stage}', '{saving,investing,fire}', 90),

('savings', 'currency_diversification',
 'Валютная диверсификация для travelers',
 'Если живёшь и зарабатываешь в одной валюте, а тратишь в разных (типичный кочевник: доход в USD, расходы в VND/THB/EUR) — держи небольшую подушку в каждой основной валюте использования. Это снимает FX-риск на повседневные расходы. Долгосрочные сбережения лучше держать в стабильной резервной валюте (USD/EUR) — они меньше подвержены девальвации развивающихся рынков. Инвестиции — в широкие международные индексы (MSCI World, FTSE All-World), а не в одну страну.',
 '{savings_advice,financial_advice,financial_stage}', '{saving,investing,fire,*}', 85),

('fire', 'fire_variants',
 'Варианты FIRE: Lean / Fat / Coast / Barista',
 'Lean FIRE: минимальные расходы (~$25k/год), цель ~$625k. Fat FIRE: комфортная жизнь ($80k+/год), цель $2M+. Coast FIRE: накопил достаточно, чтобы за счёт сложного процента к пенсии хватило — больше не обязан откладывать, можно работать на покрытие текущих расходов. Barista FIRE: частичная независимость + работа part-time для медстраховки/общения. Выбор зависит от lifestyle и личных приоритетов.',
 '{financial_advice,savings_plan,financial_stage}', '{saving,investing,fire}', 70),

('fire', 'savings_rate_table',
 'Таблица: норма сбережений → годы до FIRE',
 'При средней доходности 7% годовых после инфляции и неизменных расходах: сбережения 10% → ~51 год до FIRE. 20% → 37 лет. 30% → 28 лет. 40% → 22 года. 50% → 17 лет. 60% → 12.5 лет. 70% → 8.5 лет. 80% → 5.5 лет. Главный рычаг — норма сбережений, а не доходность инвестиций. Удвоение дохода с сохранением расходов работает мощнее, чем поиск более доходных инвестиций.',
 '{financial_advice,savings_plan,financial_stage}', '{saving,investing,fire}', 75),

('savings', 'inflation_basics',
 'Инфляция и реальная доходность',
 'Если деньги лежат под подушкой, они теряют покупательную способность на размер инфляции (исторически 2-4% в развитых странах, выше в развивающихся). "Реальная" доходность = номинальная − инфляция. Депозит под 5% при инфляции 4% даёт реальную доходность ~1%. Историческая реальная доходность акций мирового рынка ~5-7%. Облигаций ~2-3%. Поэтому долгосрочные сбережения держи в инвестициях, а не на депозите — иначе инфляция съест.',
 '{investment_basics,financial_advice,savings_advice}', '{saving,investing,fire,*}', 80),

('debt', 'debt_to_income_threshold',
 'Соотношение долг/доход (DTI)',
 'Здоровый DTI (все ежемесячные платежи по долгам / месячный валовый доход): ниже 20% — комфортно, 20-35% — приемлемо, 36-49% — стресс, 50%+ — финансовый кризис. Если DTI выше 36%, новые долги категорически не брать, фокус на погашение. Ипотека обычно одобряется при общем DTI до 43%. Используй для самопроверки перед крупной покупкой в кредит.',
 '{debt_strategy,financial_advice,financial_stage}', '{has_debt,beginner}', 85),

('psychology', 'loss_aversion',
 'Боязнь потерь (loss aversion)',
 'Человек переживает потерю 100$ примерно вдвое сильнее, чем радость от выигрыша 100$ (Канеман, нобелевская премия). На практике это значит: люди слишком долго держат убыточные инвестиции (надеются "отыграться") и слишком быстро продают прибыльные (фиксируют). Защита: автоматизация (DCA, ребалансировка по календарю) и заранее прописанные правила выхода. Не торгуй в момент паники.',
 '{financial_advice,impulse_check,book_recommendations}', '{saving,investing,fire,*}', 70),

('psychology', 'mental_accounting',
 'Ментальный учёт',
 'Мы делим деньги на "категории" в голове и относимся к ним по-разному: премию тратим легче, чем зарплату; "лишние" деньги (возврат налогов) — на развлечения. Все деньги одинаковы — рубль это рубль. Премию или возврат лучше распределить по тем же категориям бюджета: 50% сбережения, 30% желания, 20% неотложные нужды. Иначе деньги "сгорят" незаметно.',
 '{financial_advice,budget_optimization,impulse_check}', '{*}', 65),

('savings', 'travel_emergency_fund',
 'Подушка безопасности кочевника',
 'Стандарт 3-6 месяцев расходов остаётся в силе, но для жизни вне родной страны добавь: (1) buffer на экстренный билет домой ($1500-3000), (2) запас на 1-2 месяца в стабильной валюте (USD/EUR) на случай девальвации местной, (3) международная медстраховка (SafetyWing, World Nomads). Держи подушку в высоколиквидных инструментах: high-yield savings account, money market fund. Не вкладывай в акции — это не инвестиция, это страховка.',
 '{savings_advice,savings_plan,financial_advice}', '{building_emergency,saving,*}', 80),

('investing', 'avoid_individual_stocks',
 'Почему не стоит увлекаться отдельными акциями',
 'Покупка акций отдельных компаний (Apple, Tesla, Nvidia) — это не инвестирование, это спекуляция. 90% непрофессиональных трейдеров теряют деньги на горизонте 5+ лет. Даже если выберешь одного победителя, не угадаешь второго. Альтернатива: 80-90% капитала в широкий индекс, 10-20% — "fun money" на отдельные истории, если очень хочется. Богл: "не пытайся найти иголку в стоге сена — купи весь стог".',
 '{investment_basics,financial_advice,impulse_check,book_recommendations}', '{investing,fire,*}', 75),

('safety', 'high_return_red_flags',
 'Признаки финансовой пирамиды и скама',
 'Красные флаги: (1) гарантированная доходность 20%+ в год — невозможно без риска; (2) "уникальная стратегия", которую никто больше не использует; (3) давление на скорость решения; (4) сложно вывести деньги; (5) рекомендации от знакомых, а не публичная репутация; (6) платформа зарегистрирована в офшоре и нет лицензии. Если предложение звучит слишком хорошо — это так и есть. Реальные ETF на S&P 500 дают 7-10% после инфляции, и это хороший результат.',
 '{financial_safety,financial_advice}', '{*}', 90);
